CODE_EXAMPLE:
// Fast + Independent + Repeatable + Self-validating
@Test
public void order_initialStatus_isPending() {
    Order order = new Order();
    assertEquals(OrderStatus.PENDING, order.getStatus());
}

@Test
public void order_afterConfirm_isConfirmed() {
    Order order = new Order();
    order.confirm();
    assertEquals(OrderStatus.CONFIRMED, order.getStatus());
}

UNIT_TEST_EXAMPLE:
@Test
public void order_transitions_areIndependent() {
    Order o1 = new Order(); o1.confirm();
    Order o2 = new Order();
    assertEquals(OrderStatus.PENDING, o2.getStatus());
    assertEquals(OrderStatus.CONFIRMED, o1.getStatus());
}
